mapper.sql:
WITH EVAL_STATS AS ( SELECT PT.DSCS_ID, COUNT(DISTINCT AT.USER_ID) AS forumEvalCnt FROM TB_LMS_DSCS_PTCP PT JOIN TB_LMS_ATNDLC AT ON AT.USER_ID = PT.USER_ID AND AT.ATNDLC_STSCD = 'S' AND AT.AUDITYN = 'N' JOIN TB_LMS_DSCS D ON D.DSCS_ID = PT.DSCS_ID AND D.SBJCT_ID = AT.SBJCT_ID WHERE PT.DELYN = 'N' AND PT.EVLYN = 'Y' AND PT.SCR IS NOT NULL AND D.DELYN = 'N' AND D.SBJCT_ID = #{sbjctId} AND EXISTS ( SELECT 1 FROM ( SELECT DSCS_ID, USER_ID FROM TB_LMS_DSCS_ATCL WHERE DELYN = 'N' UNION ALL SELECT ATC2.DSCS_ID, CMT.USER_ID FROM TB_LMS_DSCS_CMNT CMT JOIN TB_LMS_DSCS_ATCL ATC2 ON ATC2.DSCS_ATCL_ID = CMT.DSCS_ATCL_ID WHERE CMT.DELYN = 'N' AND ATC2.DELYN = 'N' ) ACT WHERE ACT.DSCS_ID = PT.DSCS_ID AND ACT.USER_ID = PT.USER_ID ) GROUP BY PT.DSCS_ID ) SELECT ROW_NUMBER() OVER (ORDER BY A.REG_DTTM DESC, A.DSCS_ID DESC) LINE_NO , COUNT(*) OVER() TOTAL_CNT , A.DSCS_ID , A.DSCS_GRP_ID , A.DSCS_GBNCD , A.DSCS_TYCD , A.DSCS_UNIT_TYCD , A.EVL_SCR_TYCD , A.DSCS_TTL , A.DSCS_CTS , A.DSCS_SDTTM , A.DSCS_EDTTM , A.DVCLS_NO , A.LRN_GRP_ID , A.DELYN , A.OATCL_INQYN , A.OKNOK_STNGYN , A.OKNOKRT_OYN , A.OKNOK_MODYN , A.MLT_OPNN_REGYN , A.OKNOK_RGTR_OYN , A.CMNT_RSPNS_REQYN , A.MRK_RFLTYN , A.MRK_RFLTRT , A.MRK_OYN , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.SBJCT_ID , (SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN = 'N') AS forumAtclCnt , (SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT B WHERE B.DELYN = 'N' AND B.DSCS_ATCL_ID IN ( SELECT C.DSCS_ATCL_ID FROM TB_LMS_DSCS_ATCL C WHERE C.DSCS_ID = A.DSCS_ID AND C.DELYN = 'N' )) AS forumCmntCnt , (SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN = 'N' AND B.OKNOK_GBNCD = 'OK' AND B.ATCL_LV = 0) AS forumAtclPorsCnt , (SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN = 'N' AND B.OKNOK_GBNCD = 'NOTOK' AND B.ATCL_LV = 0) AS forumAtclConsCnt , ( SELECT COUNT(*) FROM TB_LMS_ATNDLC ATNDLC JOIN TB_LMS_SBJCT SBJCT ON ATNDLC.SBJCT_ID = SBJCT.SBJCT_ID WHERE ATNDLC.AUDITYN = 'N' AND SBJCT.SBJCT_ID = #{sbjctId} ) AS forumUserTotalCnt , ( SELECT COUNT(1) FROM TB_LMS_ATNDLC AA WHERE AA.SBJCT_ID = #{sbjctId} AND AA.ATNDLC_STSCD = 'S' AND AA.AUDITYN = 'N' AND ( EXISTS ( SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = A.DSCS_ID AND USER_ID = AA.USER_ID AND DELYN = 'N' ) OR EXISTS ( SELECT 1 FROM TB_LMS_DSCS_CMNT WHERE USER_ID = AA.USER_ID AND DELYN = 'N' AND DSCS_ATCL_ID IN ( SELECT DSCS_ATCL_ID FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = A.DSCS_ID AND DELYN = 'N' ) ) ) ) AS forumJoinUserCnt , NVL(S.forumEvalCnt, 0) AS forumEvalCnt , (SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN = 'N' AND RGTR_ID = #{userId}) AS forumMyAtclCnt , (SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT B WHERE B.DELYN = 'N' AND B.RGTR_ID = #{userId} AND B.DSCS_ATCL_ID IN ( SELECT C.DSCS_ATCL_ID FROM TB_LMS_DSCS_ATCL C WHERE C.DSCS_ID = A.DSCS_ID AND C.DELYN = 'N' )) AS forumMyCmntCnt
, (SELECT SCR FROM TB_LMS_DSCS_PTCP B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN = 'N' AND B.USER_ID = ( SELECT USER_ID FROM TB_LMS_ATNDLC WHERE SBJCT_ID = #{sbjctId} AND USER_ID = #{userId} AND ATNDLC_STSCD = 'S' ) ) AS forumMyScore
, CASE WHEN EXISTS ( SELECT 1 FROM TB_LMS_DSCS_FDBK B WHERE B.DSCS_ID = A.DSCS_ID AND B.USER_ID = ( SELECT USER_ID FROM TB_LMS_ATNDLC WHERE SBJCT_ID = #{sbjctId} AND USER_ID = #{userId} AND ATNDLC_STSCD = 'S' ) ) THEN 1 ELSE 0 END AS forumMyFdbk FROM TB_LMS_DSCS A LEFT JOIN EVAL_STATS S ON S.DSCS_ID = A.DSCS_ID WHERE 1 = 1 AND A.DELYN = 'N' AND A.UP_DSCS_ID IS NULL
AND A.SBJCT_ID = #{sbjctId}
AND A.DSCS_GBNCD = #{dscsGbncd}
AND A.DSCS_UNIT_TYCD = #{dscsUnitTycd}
AND A.EVL_SCR_TYCD = #{evlScrTycd}
AND A.DSCS_TTL LIKE FN_LIKE_VAL(#{dscsTtl})
AND TO_DATE(A.DSCS_SDTTM, 'YYYYMMDDHH24MISS') BETWEEN TO_DATE(#{dscsSdttm}, 'YYYYMMDDHH24MISS') AND TO_DATE(#{dscsEdttm}, 'YYYYMMDDHH24MISS')
ORDER BY A.REG_DTTM DESC, A.DSCS_ID DESC

mapper.insert:
/*
    SQL ID : Forum2DAO.insertForumGrp
    설명 : 토론그룹등록
*/
INSERT INTO TB_LMS_DSCS_GRP (
    DSCS_GRP_ID
  , DSCS_GRPNM
  , RGTR_ID
  , REG_DTTM
) VALUES (
    #{dscsGrpId}
  , #{dscsGrpnm}
  , #{rgtrId}
  , FN_DTTM()
)

mapper.update:
/*
   SQL ID : ForumDAO.updateForum
   설명 : 토론수정
*/
UPDATE TB_LMS_DSCS
SET MDFR_ID = NVL(#{mdfrId}, #{rgtrId})
  , MOD_DTTM = FN_DTTM()

  , DSCS_GRP_ID = #{dscsGrpId}


  , DSCS_GBNCD = #{dscsGbncd}


  , DSCS_UNIT_TYCD = #{dscsUnitTycd}


  , EVL_SCR_TYCD = #{evlScrTycd}


  , DSCS_TTL = #{dscsTtl}


  , DSCS_CTS = #{dscsCts}


  , DSCS_SDTTM = #{dscsSdttm}


  , DSCS_EDTTM = #{dscsEdttm}


  , DVCLS_NO = #{dvclsNo}


  , LRN_GRP_ID = #{lrnGrpId}


  , DELYN = #{delyn}


  , OATCL_INQYN = #{oatclInqyn}


  , OKNOK_STNGYN = #{oknokStngyn}


  , OKNOKRT_OYN = #{oknokrtOyn}


  , OKNOK_MODYN = #{oknokModyn}


  , MLT_OPNN_REGYN = #{mltOpnnRegyn}


  , OKNOK_RGTR_OYN = #{oknokRgtrOyn}


  , CMNT_RSPNS_REQYN = #{cmntRspnsReqyn}


  , MRK_RFLTYN = #{mrkRfltyn}


  , MRK_OYN = #{mrkOyn}


  , SBJCT_ID = #{sbjctId}


  , BYTEAM_DSCS_USEYN = #{byteamDscsUseyn}

WHERE DSCS_ID = #{dscsId}

/*
    SQL ID : Forum2DAO.updateForumMrkOyn
    설명 : 토론성적공개여부 수정
*/
UPDATE TB_LMS_DSCS
SET MRK_OYN = #{mrkOyn}
  , MDFR_ID = NVL(#{mdfrId}, #{rgtrId})
  , MOD_DTTM = FN_DTTM()
WHERE DSCS_ID = #{dscsId}
  AND DELYN = 'N'

/*
    SQL ID : Forum2DAO.updateForumMrkRfltrt
    설명 : 토론성적반영비율 수정
*/

UPDATE TB_LMS_DSCS
   SET MRK_RFLTRT = #{item.mrkRfltrt}
     , MDFR_ID = NVL(#{item.mdfrId}, #{item.rgtrId})
     , MOD_DTTM = FN_DTTM()
 WHERE DSCS_ID = #{item.dscsId}
   AND DELYN = 'N'

/*
    SQL ID : Forum2DAO.updateChildForumDtls
    설명 : 팀토론 자식 토론 제목/내용 수정
*/
UPDATE TB_LMS_DSCS
SET    DSCS_TTL  = #{dscsTtl}
     , DSCS_CTS  = #{dscsCts}
     , MDFR_ID   = NVL(#{mdfrId}, #{rgtrId})
     , MOD_DTTM  = FN_DTTM()
WHERE  UP_DSCS_ID = #{upDscsId}
  AND  TEAM_ID    = #{teamId}
  AND  DELYN      = 'N'

/*
    SQL ID : Forum2DAO.updateTeamDscsOyn
    설명 : 팀토론토론방OPEN여부 수정
*/
UPDATE TB_LMS_DSCS
SET TEAM_DSCS_OYN = #{teamDscsOyn}
  , MDFR_ID = NVL(#{mdfrId}, #{rgtrId})
  , MOD_DTTM = FN_DTTM()
WHERE DSCS_ID = #{dscsId}
  AND DELYN = 'N'

/*
    성적반영비율 초기화
    ForumDAO.setScoreRatio
*/
UPDATE TB_LMS_DSCS
SET MRK_RFLTRT = #{mrkRfltrt}
WHERE DSCS_ID = #{dscsId}
